import { useRef, type KeyboardEvent as ReactKeyboardEvent } from 'react';
import { useIntl } from 'react-intl';

import { _ChartToolbarRenderer as ChartToolbarRenderer } from '@dynatrace/strato-components/charts';
import { DownloadIcon } from '@dynatrace/strato-icons';

import { useMapRawData } from '../../../hooks/use-map-raw-data.js';
import { buildAndDownloadCsv } from '../../../utils/build-and-download-csv.js';
import { TOOLBAR_MESSAGES } from '../constants.js';
import { useA11yToolbarTabIndex } from '../hooks/use-a11y-toolbar-tab-index.js';

export const MapDownloadDataButton = () => {
  const downloadDataButtonRef = useRef<HTMLButtonElement | null>(null);
  const intl = useIntl();
  const tabIndex = useA11yToolbarTabIndex('download-data');
  const data = useMapRawData();

  /** Handles the download button when event keydown.*/
  const handleDownloadDataKeyboard = (event: ReactKeyboardEvent) => {
    if (event.key === 'Enter') {
      buildAndDownloadCsv(data);
    }
  };

  /** Handles the download button when clicked. */
  const handleDownloadDataToolbar = () => {
    buildAndDownloadCsv(data);
  };

  return (
    <ChartToolbarRenderer.Control
      ref={downloadDataButtonRef}
      prefixIcon={<DownloadIcon />}
      tooltipText={intl.formatMessage(TOOLBAR_MESSAGES.downloadData)}
      testId="map-toolbar-download"
      onKeyDown={handleDownloadDataKeyboard}
      onClick={handleDownloadDataToolbar}
      tabIndex={tabIndex}
      placement="toolbar"
    />
  );
};
